// ============================================
// Palette Selector
// Personality-agnostic, configurable via CSS custom properties
// ============================================

@use '../styles/mixins' as *;

.palette-selector {
  padding: 24px;
  background-color: #fafafa;
  color: #1f2937;
  border-radius: var(--border-radius-sm, 4px);
  border: 1px solid color-mix(in srgb, var(--primary) 12%, transparent);
  @include theme-inset-shadow;
  max-width: 800px;
  margin: 0 auto;

  h3 {
    margin: 0 0 24px 0;
    font-family: var(--font-mono, monospace);
    font-size: 0.75rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--primary);
    text-align: center;
    padding-bottom: 12px;
    border-bottom: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
  }
}

.palette-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 12px;
  margin-bottom: 24px;
}

.palette-card {
  border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
  border-radius: var(--border-radius-sm, 4px);
  padding: 16px;
  cursor: pointer;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);
  background: #fff;
  position: relative;

  &:hover {
    border-color: color-mix(in srgb, var(--primary) 40%, transparent);
    box-shadow: inset 0 1px 3px rgba(0, 0, 0, 0.05);
    transform: translateY(-1px);
  }

  &.active {
    border-color: var(--primary);
    background: color-mix(in srgb, var(--primary) 8%, transparent);
    box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.05);

    .palette-info h4 {
      color: var(--primary);
    }

    .palette-info p {
      color: #4b5563;
    }
  }
}

.palette-colors {
  display: flex;
  gap: 4px;
  margin-bottom: 10px;
}

.color-swatch {
  width: 36px;
  height: 36px;
  border-radius: 3px;
  border: 1px solid rgba(0, 0, 0, 0.1);
  flex-shrink: 0;
}

.palette-info {
  h4 {
    margin: 0 0 4px 0;
    font-family: var(--font-mono, monospace);
    font-size: 0.8125rem;
    font-weight: 500;
    color: #374151;
  }

  p {
    margin: 0;
    font-family: var(--font-mono, monospace);
    font-size: 0.6875rem;
    color: #6b7280;
    line-height: 1.4;
  }
}

.custom-mode {
  border-top: 1px solid color-mix(in srgb, var(--primary) 12%, transparent);
  padding-top: 20px;
  margin-bottom: 20px;
}

.custom-btn {
  background-color: #fff;
  color: #4b5563;
  border: 1px solid color-mix(in srgb, var(--primary) 20%, transparent);
  padding: 10px 20px;
  border-radius: 3px;
  cursor: pointer;
  font-family: var(--font-mono, monospace);
  font-size: 0.6875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);

  &:hover {
    background: color-mix(in srgb, var(--primary) 8%, transparent);
    border-color: color-mix(in srgb, var(--primary) 40%, transparent);
    color: var(--primary);
  }

  &.active {
    background: color-mix(in srgb, var(--primary) 12%, transparent);
    border-color: var(--primary);
    color: var(--primary);
  }
}

.custom-inputs {
  display: flex;
  gap: 16px;
  margin-top: 16px;
  flex-wrap: wrap;
}

.custom-inputs label {
  display: flex;
  flex-direction: column;
  gap: 6px;
  font-family: var(--font-mono, monospace);
  font-size: 0.6875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #6b7280;
}

.custom-inputs input[type='color'] {
  width: 56px;
  height: 36px;
  border: 1px solid color-mix(in srgb, var(--primary) 20%, transparent);
  border-radius: 3px;
  cursor: pointer;
  background: #fff;
  padding: 2px;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);

  &:hover {
    border-color: color-mix(in srgb, var(--primary) 40%, transparent);
  }
}

.theme-toggle {
  border-top: 1px solid color-mix(in srgb, var(--primary) 12%, transparent);
  padding-top: 20px;
  text-align: center;
}

.theme-toggle button {
  background-color: var(--primary);
  color: #ffffff;
  border: none;
  padding: 12px 24px;
  border-radius: 3px;
  cursor: pointer;
  font-family: var(--font-mono, monospace);
  font-size: 0.6875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);

  &:hover {
    background-color: var(--primary-dark, var(--primary));
    transform: translateY(-1px);
  }

  &:active {
    transform: translateY(0);
  }
}

// Palette preview in grid
.palette-preview {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-top: 12px;
  padding: 12px;
  background: #f3f4f6;
  border-radius: 3px;
  border: 1px solid color-mix(in srgb, var(--primary) 8%, transparent);

  .preview-label {
    font-family: var(--font-mono, monospace);
    font-size: 0.5625rem;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: #9ca3af;
  }

  .preview-buttons {
    display: flex;
    gap: 6px;

    button {
      padding: 4px 10px;
      font-family: var(--font-mono, monospace);
      font-size: 0.5625rem;
      text-transform: uppercase;
      letter-spacing: 0.05em;
      border-radius: 2px;
      cursor: pointer;
      transition: all var(--animation-duration-fast, 200ms)
        var(--animation-easing, ease);

      &.primary {
        background: var(--accent);
        color: white;
        border: none;
      }

      &.secondary {
        background: transparent;
        border: 1px solid var(--accent);
        color: var(--accent);
      }
    }
  }
}

/* Responsive design */
@media (max-width: 640px) {
  .palette-grid {
    grid-template-columns: 1fr;
  }

  .custom-inputs {
    flex-direction: column;
  }

  .palette-selector {
    padding: 16px;
  }
}

