styles:
.personality-preview {
  padding: 1.5rem;
  max-width: 1200px;
  margin: 0 auto;
}

.preview-header {
  text-align: center;
  margin-bottom: 2rem;

  h4 {
    margin: 0 0 0.5rem;
    font-size: 1.5rem;
    color: var(--foreground);
  }

  .subtitle {
    margin: 0;
    color: var(--muted);
    font-size: 0.9rem;
  }
}

.preview-container {
  display: flex;
  flex-direction: column;
  gap: 2rem;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--border-radius-lg, 8px);
  padding: 1.5rem;
}

.preview-section {
  .section-title {
    font-size: 0.875rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--muted);
    margin: 0 0 1rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid var(--border);
  }
}

// Typography
.typography-demo {
  h1,
  h2,
  h3 {
    margin: 0 0 0.5rem;
    color: var(--foreground);
    font-family: var(--font-heading, var(--font-body));
  }

  h1 {
    font-size: 2rem;
  }
  h2 {
    font-size: 1.5rem;
  }
  h3 {
    font-size: 1.25rem;
  }

  .body-text {
    margin: 0 0 0.5rem;
    color: var(--foreground);
    line-height: var(--line-height, 1.5);
  }

  .muted-text {
    margin: 0 0 0.5rem;
    color: var(--muted);
  }

  .code-text {
    display: inline-block;
    padding: 0.25rem 0.5rem;
    background: var(--background);
    border-radius: var(--border-radius-sm, 2px);
    font-family: var(--font-mono, monospace);
    font-size: 0.85em;
    color: var(--foreground);
  }
}

// Colors
.color-palette {
  display: flex;
  flex-direction: column;
  gap: 1rem;

  .color-group {
    display: flex;
    align-items: center;
    gap: 1rem;

    &.semantic {
      flex-direction: column;
      align-items: flex-start;
    }
  }

  .color-label {
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--muted);
    min-width: 80px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }

  .color-swatches {
    display: flex;
    gap: 0.25rem;
  }

  .color-swatch {
    width: 40px;
    height: 40px;
    border-radius: var(--border-radius-sm, 2px);
    border: 1px solid var(--border);
  }

  .semantic-colors {
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
  }

  .semantic-swatch {
    padding: 0.5rem 1rem;
    border-radius: var(--border-radius-md, 4px);
    font-size: 0.875rem;
    font-weight: 500;
    color: white;
  }
}

// Components
.components-demo {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.demo-row {
  display: flex;
  align-items: flex-start;
  gap: 1rem;

  .demo-label {
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--muted);
    min-width: 80px;
    text-transform: uppercase;
    padding-top: 0.5rem;
  }
}

.demo-buttons {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.btn {
  padding: 0.5rem 1rem;
  border: none;
  border-radius: var(--border-radius-md, 4px);
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;

  &.btn-sm {
    padding: 0.25rem 0.75rem;
    font-size: 0.75rem;
  }

  &.btn-primary {
    background: var(--primary);
    color: var(--primary-foreground);
  }

  &.btn-secondary {
    background: var(--secondary);
    color: var(--secondary-foreground);
  }

  &.btn-tertiary {
    background: var(--tertiary);
    color: var(--tertiary-foreground);
  }

  &.btn-outline {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--foreground);
  }

  &:hover {
    opacity: 0.9;
    transform: translateY(-1px);
  }
}

.demo-card {
  background: var(--background);
  border: 1px solid var(--border);
  border-radius: var(--border-radius-lg, 8px);
  padding: 1rem;
  box-shadow: var(--shadow-sm);
  max-width: 300px;

  h6 {
    margin: 0 0 0.5rem;
    font-size: 1rem;
    color: var(--foreground);
  }

  p {
    margin: 0 0 1rem;
    font-size: 0.875rem;
    color: var(--muted);
  }
}

.demo-input-group {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.demo-input,
.demo-select {
  padding: 0.5rem;
  border: 1px solid var(--border);
  border-radius: var(--border-radius-md, 4px);
  background: var(--background);
  color: var(--foreground);
  font-size: 0.875rem;

  &:focus {
    outline: none;
    border-color: var(--primary);
    box-shadow: 0 0 0 2px rgba(var(--primary-rgb), 0.1);
  }
}

.demo-alerts {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.alert {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.75rem 1rem;
  border-radius: var(--border-radius-md, 4px);
  font-size: 0.875rem;

  .alert-icon {
    font-weight: 700;
  }

  &.alert-success {
    background: rgba(var(--success-rgb), 0.1);
    color: var(--success);
    border: 1px solid var(--success);
  }

  &.alert-warning {
    background: rgba(var(--warning-rgb), 0.1);
    color: var(--warning);
    border: 1px solid var(--warning);
  }

  &.alert-danger {
    background: rgba(var(--danger-rgb), 0.1);
    color: var(--danger);
    border: 1px solid var(--danger);
  }
}

.demo-badges {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.badge {
  padding: 0.25rem 0.5rem;
  border-radius: var(--border-radius-sm, 2px);
