  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.spacing-box {
  background: var(--primary);
  color: var(--primary-foreground);
  border-radius: var(--border-radius-sm, 2px);

  .spacing-label {
    display: block;
    background: var(--surface);
    padding: 0.25rem 0.5rem;
    font-size: 0.75rem;
    font-weight: 500;
    border-radius: var(--border-radius-sm, 2px);
  }
}

// Shadows
