// Components
.components-demo {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.demo-row {
  display: flex;
  align-items: flex-start;
  gap: 1rem;

  .demo-label {
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--muted);
    min-width: 80px;
    text-transform: uppercase;
    padding-top: 0.5rem;
  }
}

.demo-buttons {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.btn {
  padding: 0.5rem 1rem;
  border: none;
  border-radius: var(--border-radius-md, 4px);
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;

  &.btn-sm {
    padding: 0.25rem 0.75rem;
    font-size: 0.75rem;
  }

  &.btn-primary {
    background: var(--primary);
    color: var(--primary-foreground);
  }

  &.btn-secondary {
    background: var(--secondary);
    color: var(--secondary-foreground);
  }

  &.btn-tertiary {
    background: var(--tertiary);
    color: var(--tertiary-foreground);
  }

  &.btn-outline {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--foreground);
  }

  &:hover {
    opacity: 0.9;
    transform: translateY(-1px);
  }
}

.demo-card {
  background: var(--background);
  border: 1px solid var(--border);
  border-radius: var(--border-radius-lg, 8px);
  padding: 1rem;
  box-shadow: var(--shadow-sm);
  max-width: 300px;

  h6 {
    margin: 0 0 0.5rem;
    font-size: 1rem;
    color: var(--foreground);
  }

  p {
    margin: 0 0 1rem;
    font-size: 0.875rem;
    color: var(--muted);
  }
}

.demo-input-group {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.demo-input,
.demo-select {
  padding: 0.5rem;
  border: 1px solid var(--border);
  border-radius: var(--border-radius-md, 4px);
  background: var(--background);
  color: var(--foreground);
  font-size: 0.875rem;

  &:focus {
    outline: none;
    border-color: var(--primary);
    box-shadow: 0 0 0 2px rgba(var(--primary-rgb), 0.1);
  }
}

.demo-alerts {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.alert {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.75rem 1rem;
  border-radius: var(--border-radius-md, 4px);
  font-size: 0.875rem;

  .alert-icon {
    font-weight: 700;
  }

  &.alert-success {
    background: rgba(var(--success-rgb), 0.1);
    color: var(--success);
    border: 1px solid var(--success);
  }

  &.alert-warning {
    background: rgba(var(--warning-rgb), 0.1);
    color: var(--warning);
    border: 1px solid var(--warning);
  }

  &.alert-danger {
    background: rgba(var(--danger-rgb), 0.1);
    color: var(--danger);
    border: 1px solid var(--danger);
  }
}

.demo-badges {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.badge {
  padding: 0.25rem 0.5rem;
  border-radius: var(--border-radius-sm, 2px);
  font-size: 0.75rem;
  font-weight: 500;

  &.badge-primary {
    background: var(--primary);
    color: var(--primary-foreground);
  }

  &.badge-secondary {
    background: var(--secondary);
    color: var(--secondary-foreground);
  }

  &.badge-tertiary {
    background: var(--tertiary);
    color: var(--tertiary-foreground);
  }

  &.badge-outline {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--foreground);
  }
}

// Spacing
.spacing-demo {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.spacing-box {
  background: var(--primary);
  color: var(--primary-foreground);
  border-radius: var(--border-radius-sm, 2px);

  .spacing-label {
    display: block;
    background: var(--surface);
    padding: 0.25rem 0.5rem;
    font-size: 0.75rem;
    font-weight: 500;
    border-radius: var(--border-radius-sm, 2px);
  }
}

// Shadows
.shadow-demo {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

.shadow-box {
  width: 100px;
  height: 60px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--border-radius-md, 4px);
  font-size: 0.75rem;
  color: var(--foreground);

  &.shadow-sm {
    box-shadow: var(--shadow-sm);
  }
  &.shadow-md {
    box-shadow: var(--shadow-md);
  }
  &.shadow-lg {
    box-shadow: var(--shadow-lg);
  }
  &.shadow-xl {
    box-shadow: var(--shadow-xl);
  }
}

// Border Radius
.radius-demo {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

.radius-box {
  width: 80px;
  height: 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--primary);
  color: var(--primary-foreground);
  font-size: 0.75rem;
  font-weight: 500;

  &.radius-none {
    border-radius: 0;
  }
  &.radius-sm {
    border-radius: var(--border-radius-sm);
  }
  &.radius-md {
    border-radius: var(--border-radius-md);
  }
  &.radius-lg {
    border-radius: var(--border-radius-lg);
  }
  &.radius-full {
    border-radius: 50%;
  }
}

// Animation
.animation-demo {
  .animation-info {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    font-size: 0.875rem;

    .anim-label {
      color: var(--muted);
    }

    .anim-value {
      color: var(--foreground);
      font-weight: 500;
    }
  }

  .animation-examples {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-top: 1rem;
  }

  .anim-box {
    width: 50px;
    height: 50px;
    background: var(--tertiary);
    border-radius: var(--border-radius-md, 4px);
    transition: all var(--animation-duration-normal, 300ms)
      var(--animation-easing, ease);

    &.animate {
      transform: translateX(100px) rotate(360deg);
      background: var(--secondary);
    }
  }
}

@media (max-width: 640px) {
  .demo-row {
    flex-direction: column;

    .demo-label {
      min-width: auto;
    }
  }

  .color-group {
    flex-direction: column;
    align-items: flex-start;
  }
}

