// ============================================
// Theme Designer
// Personality-agnostic, configurable via CSS custom properties
// ============================================

@use '../styles/mixins' as *;

.theme-designer {
  padding: 24px;
  max-width: 1200px;
  margin: 0 auto;
  @include theme-grid-background;
  min-height: 100vh;

  h2 {
    font-family: var(--font-heading, system-ui, sans-serif);
    font-size: 1.75rem;
    font-weight: 600;
    letter-spacing: -0.03em;
    margin-bottom: 24px;
    color: #1f2937;
    padding-bottom: 12px;
    border-bottom: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
  }

  h3 {
    font-family: var(--font-mono, monospace);
    font-size: 0.75rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: #4b5563;
    margin-bottom: 16px;
    padding-bottom: 8px;
    border-bottom: 1px solid color-mix(in srgb, var(--primary) 12%, transparent);
  }

  h4 {
    font-family: var(--font-mono, monospace);
    font-size: 0.8125rem;
    font-weight: 500;
    color: #374151;
    margin-bottom: 8px;
  }
}

.designer-section {
  border: 1px solid color-mix(in srgb, var(--primary) 12%, transparent);
  border-radius: var(--border-radius-sm, 4px);
  padding: 20px;
  margin-bottom: 20px;
  @include theme-inset-shadow;
  position: relative;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 4px;
    height: 100%;
    background: color-mix(in srgb, var(--primary) 15%, transparent);
    border-radius: var(--border-radius-sm, 4px) 0 0 var(--border-radius-sm, 4px);
  }
}

.theme-toggle {
  label {
    display: flex;
    align-items: center;
    gap: 12px;
    cursor: pointer;

    input[type='checkbox'] {
      width: 36px;
      height: 20px;
      cursor: pointer;
      appearance: none;
      background: #e5e7eb;
      border-radius: 3px;
      position: relative;
      transition: all var(--animation-duration-fast, 200ms)
        var(--animation-easing, ease);

      &::after {
        content: '';
        position: absolute;
        top: 2px;
        left: 2px;
        width: 14px;
        height: 14px;
        background: #fff;
        border-radius: 2px;
        box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
        transition: transform var(--animation-duration-fast, 200ms)
          var(--animation-easing, ease);
      }

      &:checked {
        background: color-mix(in srgb, var(--primary) 30%, transparent);

        &::after {
          transform: translateX(16px);
          background: var(--primary);
        }
      }
    }

    span {
      font-family: var(--font-mono, monospace);
      font-size: 0.8125rem;
      color: #4b5563;
    }
  }
}

.color-pickers {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 20px;
}

.color-picker-group {
  display: flex;
  flex-direction: column;
  gap: 8px;

  label {
    @include theme-label;
  }
}

.color-input-wrapper {
  display: flex;
  gap: 8px;
  align-items: center;

  input[type='color'] {
    width: 48px;
    height: 32px;
    border: 1px solid color-mix(in srgb, var(--primary) 20%, transparent);
    border-radius: 3px;
    cursor: pointer;
    background: #fff;
    padding: 2px;

    &:hover {
      border-color: color-mix(in srgb, var(--primary) 40%, transparent);
    }
  }

  .color-text-input {
    flex: 1;
    padding: 8px 10px;
    border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
    border-radius: 3px;
    font-family: var(--font-mono, monospace);
    font-size: 0.75rem;
    background: #fafafa;
    color: #1f2937;
    transition: all var(--animation-duration-fast, 200ms)
      var(--animation-easing, ease);

    &:focus {
      outline: none;
      border-color: var(--primary);
      background: #fff;
    }
  }
}

.gradient-controls,
.shadow-controls {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
  margin-bottom: 20px;
}

.control-group {
  display: flex;
  flex-direction: column;
  gap: 8px;

  label {
    @include theme-label;
  }

  input[type='text'],
  select {
    padding: 8px 10px;
    border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
    border-radius: 3px;
    font-family: var(--font-mono, monospace);
    font-size: 0.75rem;
    background: #fafafa;
    color: #4b5563;
    transition: all var(--animation-duration-fast, 200ms)
      var(--animation-easing, ease);

    &:focus {
      outline: none;
      border-color: var(--primary);
      background: #fff;
    }
  }

  input[type='range'] {
    width: 100%;
    height: 4px;
    background: #e5e7eb;
    border-radius: 2px;
    appearance: none;

    &::-webkit-slider-thumb {
      appearance: none;
      width: 14px;
      height: 14px;
      background: var(--primary);
      border-radius: 2px;
      cursor: pointer;
    }
  }

  span {
    font-family: var(--font-mono, monospace);
    font-size: 0.75rem;
    color: #6b7280;
  }
}

.gradient-colors,
.shadow-preview,
.gradient-preview {
  margin-bottom: 20px;
  padding: 16px;
  background: #fff;
  border: 1px solid color-mix(in srgb, var(--primary) 10%, transparent);
  border-radius: 3px;
}

.color-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-bottom: 12px;
}

.color-item {
  display: flex;
  gap: 8px;
  align-items: center;

  input[type='color'] {
    width: 40px;
    height: 28px;
    border: 1px solid color-mix(in srgb, var(--primary) 20%, transparent);
    border-radius: 3px;
    cursor: pointer;
    background: #fff;
  }

  .color-text-input {
    flex: 1;
    padding: 6px 8px;
    border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
    border-radius: 3px;
    font-family: var(--font-mono, monospace);
    font-size: 0.6875rem;
    background: #fafafa;
    color: #374151;
  }

  .btn-remove {
    width: 28px;
    height: 28px;
    background: #ef4444;
    color: white;
    border: none;
    border-radius: 3px;
    cursor: pointer;
    font-family: var(--font-mono, monospace);
    font-size: 1rem;
    line-height: 1;
    transition: all var(--animation-duration-fast, 200ms)
      var(--animation-easing, ease);

    &:hover {
      background: #dc2626;
    }
  }
}

.btn-add {
  padding: 8px 16px;
  background: #10b981;
  color: white;
  border: none;
  border-radius: 3px;
  cursor: pointer;
  font-family: var(--font-mono, monospace);
  font-size: 0.6875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);

  &:hover {
    background: #059669;
  }
}

.preview-box {
  margin-bottom: 12px;
  border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
  border-radius: 3px;
  padding: 16px;
  background: #fff;
}

.preview-code {
  display: flex;
  gap: 8px;
  align-items: center;
  background: #1f2937;
  padding: 12px 16px;
  border-radius: 3px;

  code {
    flex: 1;
    font-family: var(--font-mono, monospace);
    font-size: 0.75rem;
    color: #e5e7eb;
    word-break: break-all;
    line-height: 1.5;
  }

  .btn-copy {
    padding: 6px 12px;
    background: var(--primary);
    color: white;
    border: none;
    border-radius: 3px;
    cursor: pointer;
    font-family: var(--font-mono, monospace);
    font-size: 0.625rem;
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    white-space: nowrap;
    transition: all var(--animation-duration-fast, 200ms)
      var(--animation-easing, ease);

    &:hover {
      background: var(--primary-dark, var(--primary));
    }
  }
}

.gradient-presets,
.shadow-presets {
  margin-top: 20px;
}

.presets-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
  gap: 8px;
}

.preset-btn {
  padding: 8px 12px;
  background: #fff;
  color: #4b5563;
  border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
  border-radius: 3px;
  cursor: pointer;
  font-family: var(--font-mono, monospace);
  font-size: 0.625rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);

  &:hover {
    background: color-mix(in srgb, var(--primary) 10%, transparent);
    border-color: var(--primary);
    color: var(--primary);
  }
}

// Palette Management Styles
.palette-selection {
  margin-bottom: 20px;
}

.palettes-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 12px;
  margin-bottom: 12px;
}

.palette-btn {
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 12px;
  background: #fff;
  border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
  border-radius: 3px;
  cursor: pointer;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);

  &.active {
    border-color: var(--primary);
    background: color-mix(in srgb, var(--primary) 5%, transparent);
    box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.05);
  }

  &:hover {
    border-color: color-mix(in srgb, var(--primary) 40%, transparent);
    box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.03);
  }

  .palette-name {
    font-family: var(--font-mono, monospace);
    font-size: 0.75rem;
    font-weight: 500;
    color: #374151;
  }

  .palette-colors {
    display: flex;
    gap: 4px;

    .color-dot {
      width: 20px;
      height: 20px;
      border-radius: 3px;
      border: 1px solid rgba(0, 0, 0, 0.1);
    }
  }

  .btn-edit-palette,
  .btn-delete-palette {
    position: absolute;
    top: 8px;
    width: 24px;
    height: 24px;
    border: none;
    border-radius: 3px;
    cursor: pointer;
    font-size: 0.75rem;
    line-height: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all var(--animation-duration-fast, 200ms)
      var(--animation-easing, ease);
  }

  .btn-edit-palette {
    right: 32px;
    background: var(--primary);
    color: white;

    &:hover {
      background: var(--primary-dark, var(--primary));
    }
  }

  .btn-delete-palette {
    right: 8px;
    background: #ef4444;
    color: white;

    &:hover {
      background: #dc2626;
    }
  }
}

.btn-create-palette {
  padding: 10px 20px;
  background: #10b981;
  color: white;
  border: none;
  border-radius: 3px;
  cursor: pointer;
  font-family: var(--font-mono, monospace);
  font-size: 0.6875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  transition: all var(--animation-duration-fast, 200ms)
    var(--animation-easing, ease);

  &:hover {
    background: #059669;
  }
}

.palette-form {
  padding: 20px;
  background: #fafafa;
  border: 1px solid color-mix(in srgb, var(--primary) 10%, transparent);
  border-radius: 3px;
  margin-top: 12px;

  form {
    display: flex;
    flex-direction: column;
    gap: 16px;
  }

  .form-group {
    display: flex;
    flex-direction: column;
    gap: 6px;

    label {
      @include theme-label;
    }

    input[type='text'] {
      padding: 8px 10px;
      border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
      border-radius: 3px;
      font-family: var(--font-mono, monospace);
      font-size: 0.8125rem;
      background: #fff;
      color: #374151;

      &:focus {
        outline: none;
        border-color: var(--primary);
      }
    }
  }

  .form-actions {
    display: flex;
    gap: 12px;
    justify-content: flex-end;
    margin-top: 8px;

    button {
      padding: 8px 16px;
      border: none;
      border-radius: 3px;
      cursor: pointer;
      font-family: var(--font-mono, monospace);
      font-size: 0.6875rem;
      font-weight: 500;
      text-transform: uppercase;
      letter-spacing: 0.05em;
      transition: all var(--animation-duration-fast, 200ms)
        var(--animation-easing, ease);
    }

    .btn-cancel {
      background: #fff;
      color: #4b5563;
      border: 1px solid color-mix(in srgb, var(--primary) 20%, transparent);

      &:hover {
        background: #f3f4f6;
      }
    }

    .btn-save {
      background: var(--primary);
      color: white;

      &:hover {
        background: var(--primary-dark, var(--primary));
      }
    }
  }
}

// Responsive
@media (max-width: 640px) {
  .theme-designer {
    padding: 16px;
  }

  .color-pickers,
  .gradient-controls,
  .shadow-controls {
    grid-template-columns: 1fr;
  }

  .palettes-grid {
    grid-template-columns: 1fr;
  }
